+
+    unsafe extern "C" fn dtor2(_obj: *mut std::ffi::c_void) {
+        DTOR2_COUNT.fetch_add(1, Ordering::SeqCst);
+    }
+
+    let handle = std::thread::spawn(|| {
+        DTOR2_COUNT.store(0, Ordering::SeqCst);
+
+        // Register and call.
+        let rc = unsafe {
